/**
 * v2.0: Narrative tense.
 * Lesson from Trauma: first-person present tense was critical but only in voice text.
 */
export interface TenseSetting extends langium.AstNode {
    readonly $container: GenerateBlock;
    readonly $type: 'TenseSetting';
    value: TenseType;
}

export const TenseSetting = {
    $type: 'TenseSetting',
    value: 'value'
} as const;

export function isTenseSetting(item: unknown): item is TenseSetting {
    return reflection.isInstance(item, TenseSetting.$type);
}

export type TenseType = 'Future' | 'Past' | 'Present';

export function isTenseType(item: unknown): item is TenseType {
    return item === 'Past' || item === 'Present' || item === 'Future';
}

/** The opposing thematic force — what the theme argues against */
export interface ThemeCounterProp extends langium.AstNode {
    readonly $container: ThemeDef;
    readonly $type: 'ThemeCounterProp';
    value: string;
}

export const ThemeCounterProp = {
    $type: 'ThemeCounterProp',
    value: 'value'
} as const;

export function isThemeCounterProp(item: unknown): item is ThemeCounterProp {
    return reflection.isInstance(item, ThemeCounterProp.$type);
}

/**
 * Story-level thematic declarations.
 * 
 * Lesson: Every story had implicit themes that shaped generation but lived only
 * in comments or character notes. Melanin's "cultivate vs. harvest" and Trauma's
 * "seeing vs. being seen" would have been better as first-class constructs.
 * 
 * Themes give the runtime a semantic compass for narrative coherence.
 */
export interface ThemeDef extends langium.AstNode {
    readonly $container: Story;
    readonly $type: 'ThemeDef';
    name: DefinitionName;
    properties: Array<ThemeProperty>;
}

export const ThemeDef = {
    $type: 'ThemeDef',
    name: 'name',
    properties: 'properties'
} as const;

export function isThemeDef(item: unknown): item is ThemeDef {
    return reflection.isInstance(item, ThemeDef.$type);
}

/** Recurring images, objects, or patterns that embody the theme */
