/**
 * Non-linear temporal structure.
 * 
 * Lesson from Infancy: the story spanned multiple lifetimes, with present-day
 * scenes intercut with past-life echoes. The grammar had no way to express
 * temporal layers or non-linear ordering.
 * 
 * Lesson from Trauma: the narrative existed outside normal time — memory
 * and present were superimposed. A timeline with a 'Collapsed' structure
 * would have signaled this to the runtime.
 */
export interface TimelineDef extends langium.AstNode {
    readonly $container: Story;
    readonly $type: 'TimelineDef';
    name: DefinitionName;
    properties: Array<TimelineProperty>;
}

export const TimelineDef = {
    $type: 'TimelineDef',
    name: 'name',
    properties: 'properties'
} as const;

export function isTimelineDef(item: unknown): item is TimelineDef {
    return reflection.isInstance(item, TimelineDef.$type);
}

export interface TimelineLayer extends langium.AstNode {
    readonly $container: TimelineLayersProp;
    readonly $type: 'TimelineLayer';
    name: DefinitionName;
    properties: Array<TimelineLayerProperty>;
}

export const TimelineLayer = {
    $type: 'TimelineLayer',
    name: 'name',
    properties: 'properties'
} as const;

export function isTimelineLayer(item: unknown): item is TimelineLayer {
    return reflection.isInstance(item, TimelineLayer.$type);
}

export type TimelineLayerProperty = LayerDescProp | LayerPeriodProp;

export const TimelineLayerProperty = {
    $type: 'TimelineLayerProperty'
} as const;

export function isTimelineLayerProperty(item: unknown): item is TimelineLayerProperty {
    return reflection.isInstance(item, TimelineLayerProperty.$type);
}

/**
 * Named temporal layers that scenes can reference.
 * E.g., "PastLife", "Present", "CosmicTime" for Infancy.
 */
export interface TimelineLayersProp extends langium.AstNode {
    readonly $container: TimelineDef;
    readonly $type: 'TimelineLayersProp';
    layers: Array<TimelineLayer>;
}

export const TimelineLayersProp = {
    $type: 'TimelineLayersProp',
    layers: 'layers'
} as const;

export function isTimelineLayersProp(item: unknown): item is TimelineLayersProp {
    return reflection.isInstance(item, TimelineLayersProp.$type);
}

export type TimelineProperty = TimelineLayersProp | TimelineSpanProp | TimelineStructureProp;

export const TimelineProperty = {
    $type: 'TimelineProperty'
} as const;

export function isTimelineProperty(item: unknown): item is TimelineProperty {
    return reflection.isInstance(item, TimelineProperty.$type);
}

/** The temporal span of the narrative */
export interface TimelineSpanProp extends langium.AstNode {
    readonly $container: TimelineDef;
    readonly $type: 'TimelineSpanProp';
    value: string;
}

export const TimelineSpanProp = {
    $type: 'TimelineSpanProp',
    value: 'value'
} as const;

export function isTimelineSpanProp(item: unknown): item is TimelineSpanProp {
    return reflection.isInstance(item, TimelineSpanProp.$type);
}

export type TimelineStructure = 'Collapsed' | 'Cyclical' | 'Linear' | 'Nonlinear' | 'Parallel' | 'Reverse';

export function isTimelineStructure(item: unknown): item is TimelineStructure {
    return item === 'Linear' || item === 'Nonlinear' || item === 'Parallel' || item === 'Collapsed' || item === 'Cyclical' || item === 'Reverse';
}

/** How time is organized in this narrative */
export interface TimelineStructureProp extends langium.AstNode {
    readonly $container: TimelineDef;
    readonly $type: 'TimelineStructureProp';
    value: TimelineStructure;
}

export const TimelineStructureProp = {
    $type: 'TimelineStructureProp',
    value: 'value'
} as const;

export function isTimelineStructureProp(item: unknown): item is TimelineStructureProp {
    return reflection.isInstance(item, TimelineStructureProp.$type);
}

/**
 * v2.0: Emotional register of the narrative.
 * Lesson from Trauma vs. Morning Tiger: wildly different tones, both unspecified.
 * Accepts string array for layered tones (e.g., ["dark", "intimate", "ironic"]).
 */
export interface ToneSetting extends langium.AstNode {
    readonly $container: GenerateBlock;
    readonly $type: 'ToneSetting';
    values: Array<string>;
}

export const ToneSetting = {
    $type: 'ToneSetting',
    values: 'values'
} as const;

export function isToneSetting(item: unknown): item is ToneSetting {
    return reflection.isInstance(item, ToneSetting.$type);
}

export type TransitionType = 'Cut' | 'Dissolve' | 'Fade' | 'FlashForward' | 'Flashback' | 'Montage' | 'Parallel' | 'Smash';

export function isTransitionType(item: unknown): item is TransitionType {
    return item === 'Cut' || item === 'Dissolve' || item === 'Flashback' || item === 'FlashForward' || item === 'Parallel' || item === 'Smash' || item === 'Fade' || item === 'Montage';
}

/**
 * Voice specification — how the character speaks and thinks.
 * This is the most critical property for multi-agent generation.
 * 
 * Lesson across all stories: voice text did the heaviest lifting.
 * Rich voice descriptions produced the most distinctive output.
 */
export interface VoiceProp extends langium.AstNode {
    readonly $container: CharacterDef;
    readonly $type: 'VoiceProp';
    value: string;
}

export const VoiceProp = {
    $type: 'VoiceProp',
    value: 'value'
} as const;

export function isVoiceProp(item: unknown): item is VoiceProp {
    return reflection.isInstance(item, VoiceProp.$type);
}

/**
 * World encapsulates setting, locations, and governing rules.
 * 
 * v2.0: Added period, sensory palette, and categorized rules.
 * Lesson from Trauma: the world was primarily sensory (fog, mirrors, echoes) 
 * but the grammar only supported named locations and flat rule strings.
 * Lesson from Infancy: needed metaphysical rules distinct from physical ones.
 */
export interface WorldDef extends langium.AstNode {
    readonly $container: Story;
    readonly $type: 'WorldDef';
    name: DefinitionName;
    properties: Array<WorldProperty>;
}

export const WorldDef = {
    $type: 'WorldDef',
    name: 'name',
    properties: 'properties'
} as const;

export function isWorldDef(item: unknown): item is WorldDef {
    return reflection.isInstance(item, WorldDef.$type);
}

/**
 * v2.0: Temporal anchoring.
 * Lesson: Every story specified its time period in comments or world descriptions.
 */
export interface WorldPeriodProp extends langium.AstNode {
    readonly $container: WorldDef;
    readonly $type: 'WorldPeriodProp';
    value: string;
}

export const WorldPeriodProp = {
    $type: 'WorldPeriodProp',
    value: 'value'
} as const;

export function isWorldPeriodProp(item: unknown): item is WorldPeriodProp {
    return reflection.isInstance(item, WorldPeriodProp.$type);
}

export type WorldProperty = LocationBlock | RuleBlock | WorldPeriodProp | WorldSensoryProp;

export const WorldProperty = {
    $type: 'WorldProperty'
} as const;

export function isWorldProperty(item: unknown): item is WorldProperty {
    return reflection.isInstance(item, WorldProperty.$type);
}

/**
 * v2.0: Dominant sensory characteristics of the world.
 * Lesson from Trauma: fog, dampness, muffled sound, cold glass — the sensory
 * palette was the entire world, but could only be expressed in location descriptions.
 * A story-level sensory specification lets the runtime maintain atmospheric coherence.
 */
export interface WorldSensoryProp extends langium.AstNode {
    readonly $container: WorldDef;
    readonly $type: 'WorldSensoryProp';
    senses: Array<string>;
}

export const WorldSensoryProp = {
    $type: 'WorldSensoryProp',
    senses: 'senses'
} as const;

export function isWorldSensoryProp(item: unknown): item is WorldSensoryProp {
    return reflection.isInstance(item, WorldSensoryProp.$type);
}

